import { z } from "zod";

export const summarizeRequestSchema = z
  .object({
    text: z.string().max(100000).optional(),
    url: z.string().url().max(2048).optional(),
    maxLength: z.number().int().min(50).max(5000).optional().default(500),
    format: z.enum(["bullets", "paragraph"]).optional().default("paragraph"),
  })
  .refine((data) => data.text || data.url, {
    message: "Either text or url must be provided",
  });

export const summarizeResponseSchema = z.object({
  summary: z.string(),
  format: z.string(),
  originalLength: z.number(),
  summaryLength: z.number(),
});

export type SummarizeRequest = z.infer<typeof summarizeRequestSchema>;
export type SummarizeResponse = z.infer<typeof summarizeResponseSchema>;
